INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f9c2f5f7-b611-4d2b-9091-c9c5d275d7f4',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC Subscriptions — Real-Time Without GraphQL's Schema Overhead$escape$,
  $escape$tRPC's subscription procedures use observables over WebSockets, giving you GraphQL-subscription semantics with zero schema boilerplate. Define one with `.subscription()` returning an `observable<T>` — tRPC's client auto-reconnects and `useSubscription` gives you `data`, `error`, and `status` typed end-to-end.

For the N+1 equivalent: tRPC's HTTP batching (on by default) coalesces parallel `useQuery` calls into a single `?batch=1` request. Unlike DataLoader's per-resolver deduplication, tRPC batches at the transport layer — no wiring, no context injection. Disable per-procedure with `httpBatchLink` options if a query must not be batched.

Router composition replaces GraphQL schema stitching: nest routers via `router({ chat: chatRouter, user: userRouter })` to build typed sub-graphs. Subscriptions live in the same router, share the same `ctx`, and type-check through to the client. There's no SDL, no resolver map, no codegen step. The TypeScript inference chain — from `observable<T>` on the server to `data: T` on the client — is the schema.$escape$,
  $escape$// server: chat.router.ts
export const chatRouter = router({
  onMessage: publicProcedure
    .input(z.object({ roomId: z.string() }))
    .subscription(({ input }) =>
      observable<Message>((emit) => {
        const handler = (msg: Message) => emit.next(msg);
        ee.on(`room:${input.roomId}`, handler);
        return () => ee.off(`room:${input.roomId}`, handler);
      })
    ),
});

// client: Chat.tsx
trpc.chat.onMessage.useSubscription(
  { roomId },
  { onData: (msg) => setMessages((prev) => [...prev, msg]) }
);$escape$,
  $escape$typescript$escape$,
