INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81e7de43-e27d-46de-944d-e416c4a4302f',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC + OpenAPI — Going Code-First Without Locking Out REST Consumers$escape$,
  $escape$tRPC is inherently code-first — your TypeScript types are the contract, not a YAML file. But when mobile teams or third-party integrations demand OpenAPI, `trpc-openapi` bridges the gap without abandoning type safety.

Annotate any procedure with `.meta({ openapi: { method: 'GET', path: '/users/{id}' } })`, then call `generateOpenApiDocument(appRouter, { title, version, baseUrl })` to produce a valid OpenAPI 3.0 spec derived directly from the router. The router stays the source of truth — the spec is a build artifact, never hand-edited.

For client generation, pipe that spec into `openapi-typescript` or `swagger-codegen`. External consumers hit REST-compatible endpoints via `createOpenApiNextHandler`, while internal Next.js callers still use `createTRPCProxyClient` for full type inference and batching.

Two constraints to know upfront: `trpc-openapi` requires Zod on both `.input()` and `.output()` — no raw-type procedures — and OpenAPI routes lose tRPC's request batching. Neither affects non-annotated procedures, so adoption is incremental.$escape$,
  $escape$import { initTRPC } from '@trpc/server';
import { generateOpenApiDocument } from 'trpc-openapi';
import { z } from 'zod';

const t = initTRPC.create();

export const appRouter = t.router({
  getUser: t.procedure
    .meta({ openapi: { method: 'GET', path: '/users/{id}' } })
    .input(z.object({ id: z.string() }))
    .output(z.object({ id: z.string(), name: z.string() }))
    .query(({ input }) => db.users.findById(input.id)),
});

export const openApiDocument = generateOpenApiDocument(appRouter, {
  title: 'ByteAI API',
  version: '1.0.0',
  baseUrl: 'https://api.byteai.dev',
});$escape$,
  $escape$typescript$escape$,
