INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ac609801-ae34-436a-9e1a-6ded954ae49f',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC — Type-Safe Filtering & Sorting Without Query String Chaos$escape$,
  $escape$tRPC procedures accept structured Zod-validated input objects, so filtering and sorting never devolve into stringly-typed query params. Define a reusable filter schema with `z.object()` and pass it directly to your `.input()` call — the client gets full autocomplete, the server gets runtime validation, no manual parsing.

For sorting, model direction as a Zod enum (`z.enum(['asc', 'desc'])`) and field as a string literal union. This mirrors what you'd express as GraphQL args or protobuf `OrderBy` fields, but with zero codegen — the schema IS the contract.

Pagination pairs naturally: use `cursor` + `limit` on the same input object. On the Prisma side, destructure directly into `findMany({ where, orderBy, take, cursor })`. tRPC's transformer layer (via `superjson`) handles Date objects in filters transparently, unlike REST query params where you'd coerce strings manually.

Avoid spreading filter state into individual procedure inputs — consolidate into a single `filters` sub-object using `z.object()` nesting so callers can partially override with `trpc.posts.list.useQuery({ filters: { status: 'published' } })`.$escape$,
  $escape$import { z } from 'zod';
import { router, publicProcedure } from '../trpc';

const postFiltersSchema = z.object({
  status: z.enum(['draft', 'published']).optional(),
  authorId: z.string().uuid().optional(),
  createdAfter: z.date().optional(),
  orderBy: z.enum(['createdAt', 'likes']).default('createdAt'),
  direction: z.enum(['asc', 'desc']).default('desc'),
  cursor: z.string().optional(),
  limit: z.number().min(1).max(100).default(20),
});

export const postRouter = router({
  list: publicProcedure
    .input(postFiltersSchema)
    .query(async ({ ctx, input }) => {
      const { status, authorId, createdAfter, orderBy, direction, cursor, limit } = input;
      return ctx.db.post.findMany({
        where: {
          ...(status && { status }),
          ...(authorId && { authorId }),
          ...(createdAfter && { createdAt: { gte: createdAfter } }),
        },
        orderBy: { [orderBy]: direction },
        take: limit,
        ...(cursor && { cursor: { id: cursor }, skip: 1 }),
      });
    }),
});$escape$,
  $escape$typescript$escape$,
