INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '166cde1a-66d4-43bc-a71d-4cbcfac95083',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC Testing — Contract, Mocking, and Integration Without REST Overhead$escape$,
  $escape$tRPC's type-safe contract lives entirely in your router definition — so contract testing means asserting your router's inferred types and procedure signatures haven't regressed, not validating HTTP schemas. Use `createCallerFactory` for integration tests: it bypasses HTTP entirely, calling procedures directly with full type inference and real middleware execution. This lets you test auth guards, input validation via Zod, and business logic in one pass without spinning up a server.

For unit tests, mock the context object instead of the router itself. Inject a fake `ctx` with stubbed `db` or `user` values into `createCaller(ctx)` — this isolates procedure logic without touching transport. Avoid mocking the tRPC client in frontend tests; use `@trpc/server/adapters/fetch` with `msw` to intercept at the fetch layer instead, preserving the real client stack. For true contract regression, pair `zod` schema snapshots with `vitest` — serialize your input/output schemas and diff them across commits to catch breaking changes before they reach clients.$escape$,
  $escape$import { createCallerFactory } from '@trpc/server';
import { appRouter } from '../router';
import { createInnerContext } from '../context';

const createCaller = createCallerFactory(appRouter);

test('getUser returns user for valid session', async () => {
  const ctx = await createInnerContext({
    user: { id: 'user_123', role: 'admin' },
    db: mockDb,
  });
  const caller = createCaller(ctx);
  const result = await caller.user.getById({ id: 'user_123' });
  expect(result.id).toBe('user_123');
});$escape$,
  $escape$typescript$escape$,
