INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1b602254-31a3-4a7b-aca6-8b824c901875',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC Error Handling — Consistent problem+json Across HTTP and WebSocket$escape$,
  $escape$tRPC normalizes errors through a single `errorFormatter` — defined once in `initTRPC.create()`, it fires for every procedure failure across HTTP and WebSocket transports alike. Without it, clients receive tRPC's raw shape (`code`, `message`, `data`), which diverges from RFC 7807 problem+json expected by many API consumers.

The formatter receives `shape` (tRPC's normalized output) and `error` (the original `TRPCError` or wrapped cause). Inject a `problem` field into `shape.data` using `shape.data.httpStatus` for the status integer and `error.code` for the title. The `type` URI acts as a machine-readable error namespace — tRPC codes like `NOT_FOUND` and `BAD_REQUEST` map cleanly to unique URIs.

Because tRPC serializes the formatted shape over both HTTP (JSON body) and WebSocket (message envelope), you get one source of truth for error structure. Pair this with a `error.cause instanceof ZodError` check inside the formatter to surface field-level validation failures in the `detail` field without breaking the RFC 7807 contract.$escape$,
  $escape$import { initTRPC, TRPCError } from '@trpc/server';
import { ZodError } from 'zod';

const t = initTRPC.create({
  errorFormatter({ shape, error }) {
    return {
      ...shape,
      data: {
        ...shape.data,
        problem: {
          type: `https://api.example.com/errors/${shape.data.code.toLowerCase()}`,
          title: error.code,
          status: shape.data.httpStatus,
          detail: error.cause instanceof ZodError
            ? error.cause.issues.map(i => i.message).join(', ')
            : error.message,
        },
      },
    };
  },
});

export const userRouter = t.router({
  get: t.procedure.input(z.string().uuid()).query(({ input }) => {
    throw new TRPCError({ code: 'NOT_FOUND', message: `User ${input} not found` });
  }),
});$escape$,
  $escape$typescript$escape$,
