INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'da0e4e90-1f5b-4c11-b5df-ba6f49e91b0f',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC Security — Zod Boundaries, CSRF, and Procedure Exposure$escape$,
  $escape$TypeScript types vanish at runtime. A tRPC procedure without `.input()` accepts arbitrary payloads — no type error, no warning. Every public and protected procedure must declare an explicit Zod schema via `.input()`; this is your only runtime validation boundary, and it's where injection is stopped.

CSRF is not handled automatically by tRPC's HTTP adapter. The `createHTTPHandler` and `fetchRequestHandler` don't restrict cross-origin requests unless you configure CORS explicitly. Pair the adapter with a CORS middleware that whitelists known origins, and for mutation-heavy APIs, validate the `Origin` or `Referer` header inside a reusable `t.middleware()`.

tRPC has no introspection endpoint like GraphQL, but your router shape leaks if you import server-side router types into client bundles — a common mistake when sharing a monorepo `AppRouter` type without tree-shaking boundaries. Export only the type (`export type AppRouter`), never the runtime router. Use `t.procedure.use(isAuthed)` on every non-public procedure; an unguarded `.query()` on a protected resource is invisible to tRPC's type system but fully exploitable at runtime.$escape$,
  $escape$import { z } from 'zod';
import { TRPCError } from '@trpc/server';
import { t } from './trpc-init';

// Enforce origin for CSRF protection on mutations
const csrfMiddleware = t.middleware(({ ctx, next }) => {
  const origin = ctx.req.headers['origin'];
  if (!origin || !process.env.ALLOWED_ORIGINS!.split(',').includes(origin)) {
    throw new TRPCError({ code: 'FORBIDDEN', message: 'Invalid origin' });
  }
  return next();
});

export const secureProcedure = t.procedure.use(csrfMiddleware);

export const updateProfileRouter = t.router({
  update: secureProcedure
    .input(z.object({ bio: z.string().max(160).trim() })) // runtime boundary
    .mutation(({ input, ctx }) => saveProfile(ctx.userId, input.bio)),
});$escape$,
