INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '191958fe-b5e4-476e-b513-7168ee3024f2',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC — REST vs GraphQL vs gRPC: A Decision Framework for tRPC Users$escape$,
  $escape$tRPC sidesteps the REST vs GraphQL vs gRPC debate for TypeScript monorepos — you get end-to-end type safety with zero schema duplication. But knowing when to step outside tRPC matters as systems grow.

Stay in tRPC when your client and server share a TypeScript codebase (Next.js, React + Node), you want automatic request batching via `httpBatchLink`, or you need subscriptions via `wsLink` without GraphQL's resolver overhead.

Reach for REST when building a public API consumed by non-TS clients or when you need HTTP caching semantics (ETags, CDN-friendly GETs). tRPC queries use GET by default, but the RPC shape breaks standard REST conventions that third-party consumers expect.

Reach for gRPC for high-throughput inter-service communication or bidirectional HTTP/2 streaming — tRPC subscriptions use WebSocket, not HTTP/2 streams, so latency-sensitive internal services benefit from gRPC's binary framing.

Skip GraphQL unless multiple independent consumer teams need client-driven query shaping. tRPC's `.select()` transformer achieves similar payload trimming without a resolver layer or schema file. Use `splitLink` to route tRPC procedures and legacy REST calls through the same client.$escape$,
  $escape$import { createTRPCClient, httpBatchLink, splitLink, wsLink, createWSClient } from '@trpc/client';
import type { AppRouter } from '../server/router';

const wsClient = createWSClient({ url: 'ws://localhost:3001' });

const client = createTRPCClient<AppRouter>({
  links: [
    splitLink({
      condition: (op) => op.type === 'subscription',
      true: wsLink({ client: wsClient }),        // WebSocket for subscriptions
      false: httpBatchLink({ url: '/api/trpc' }), // Batched HTTP for queries/mutations
    }),
  ],
});

// Type-safe RPC — no .proto files, no GraphQL schema, no REST endpoint guessing
const user = await client.user.getById.query({ id: '123' });$escape$,
  $escape$typescript$escape$,
